package com.eas.ui.user;
import com.eas.config.Database; import com.eas.model.UserSession; import com.eas.service.AuditService; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class MyLeavePanel extends UserTablePanel { private final JTextField typeId=new JTextField(5),start=new JTextField(10),end=new JTextField(10),days=new JTextField(5),reason=new JTextField(28); public MyLeavePanel(UserSession s){super(s,"My Leave Requests","SELECT l.id,lt.leave_name,l.start_date,l.end_date,l.total_days,l.reason,l.status,l.admin_remarks FROM employees e JOIN leave_requests l ON e.id=l.employee_id JOIN leave_types lt ON l.leave_type_id=lt.id WHERE e.user_id=? ORDER BY l.id DESC","SELECT l.id,lt.leave_name,l.start_date,l.end_date,l.total_days,l.reason,l.status,l.admin_remarks FROM employees e JOIN leave_requests l ON e.id=l.employee_id JOIN leave_types lt ON l.leave_type_id=lt.id WHERE e.user_id=? AND (lt.leave_name LIKE ? OR l.status LIKE ? OR l.reason LIKE ?) ORDER BY l.id DESC",true);JPanel p=new JPanel();p.setBorder(BorderFactory.createTitledBorder("File Leave Request: Type IDs in Leave Types tab"));p.add(new JLabel("Type ID"));p.add(typeId);p.add(new JLabel("Start"));p.add(start);p.add(new JLabel("End"));p.add(end);p.add(new JLabel("Days"));p.add(days);p.add(reason);JButton submit=UITheme.button("SUBMIT");JButton cancel=UITheme.button("CANCEL SELECTED PENDING");p.add(submit);p.add(cancel);add(p,BorderLayout.SOUTH);submit.addActionListener(e->submit());cancel.addActionListener(e->cancel());}
 private void submit(){String q="INSERT INTO leave_requests(employee_id,leave_type_id,start_date,end_date,total_days,reason) SELECT id,?,?,?,?,? FROM employees WHERE user_id=?";try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement(q)){p.setString(1,typeId.getText().trim());p.setString(2,start.getText().trim());p.setString(3,end.getText().trim());p.setString(4,days.getText().trim());p.setString(5,reason.getText().trim());p.setInt(6,session.getId());p.executeUpdate();AuditService.log(session.getId(),"SUBMIT","LEAVE","Filed leave request.");load("");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
 private void cancel(){int r=table.getSelectedRow();if(r<0)return;try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement("UPDATE leave_requests l JOIN employees e ON l.employee_id=e.id SET l.status='CANCELLED' WHERE l.id=? AND e.user_id=? AND l.status='PENDING'")){p.setInt(1,Integer.parseInt(table.getValueAt(r,0).toString()));p.setInt(2,session.getId());p.executeUpdate();load("");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
}
